using MultiGridBarrier
using Test
using LinearAlgebra

# Compact reference-comparison tests, one mgb_solve per (function, p) variant.
# Each reference vector was captured from the current solver — adjust `tol`
# below if you intentionally tweak stopping criteria, AMG settings, etc.
const algebraic_tol = 1e-6

@testset "Algebraic multigrid front-ends" begin

    nodes5 = collect(range(-1.0, 1.0, length=5))                 # 4 elements

    # ─── fem1d ─────────────────────────────────────────────────
